import shioaji as _sj

_EXPORTS = {"Watchlist": "Watchlist"}

__all__ = ("Watchlist",)


def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.watchlist.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.watchlist' has no attribute {name!r}")
